Code Good:
use std::ffi::{CStr, CString};

extern "C" {
    fn c_greet(name: *const std::os::raw::c_char);
}

pub fn greet(name: &str) {
    let c_name = CString::new(name)
        .expect("name must not contain null bytes");
    // SAFETY: c_name is a valid null-terminated C string
    // and c_greet does not store the pointer beyond this call.
    unsafe { c_greet(c_name.as_ptr()) }
}

Code Bad:
