    fn c_greet(name: *const u8);
}

fn greet(name: &str) {
    // Rust strings are NOT null-terminated!
    unsafe { c_greet(name.as_ptr()) }
    // UB: C function reads past string end
}

Code Good:
fn process_ptr(ptr: *const u8, len: usize) -> Option<Vec<u8>> {
    if ptr.is_null() {
        return None;
    }
    // SAFETY: ptr is non-null (checked above), properly aligned
    // (u8 alignment is 1), and points to `len` initialized bytes
    // as guaranteed by the caller's contract.
    let slice = unsafe { std::slice::from_raw_parts(ptr, len) };
    Some(slice.to_vec())
}

