struct MyBuffer {
    ptr: *mut u8,
    len: usize,
}

// SAFETY: MyBuffer owns its allocation exclusively.
// The pointer is not shared with other threads.
// All access is through &self (shared) or &mut self (exclusive).
unsafe impl Send for MyBuffer {}

// SAFETY: All methods taking &self only read through the pointer.
// No interior mutability through shared references.
unsafe impl Sync for MyBuffer {}

