Code Good:
use std::arch::asm;

fn cpuid(leaf: u32) -> (u32, u32, u32, u32) {
    let (eax, ebx, ecx, edx);
    // SAFETY: cpuid is available on all x86_64 processors.
    // The registers are correctly specified as outputs.
    unsafe {
        asm!(
            "cpuid",
            inlateout("eax") leaf => eax,
            lateout("ebx") ebx,
            lateout("ecx") ecx,
            lateout("edx") edx,
        );
    }
    (eax, ebx, ecx, edx)
}

