#[repr(C)]
union FloatBits {
    f: f32,
    bits: u32,
}

fn float_to_bits(f: f32) -> u32 {
    let fb = FloatBits { f };
    // SAFETY: f32 and u32 have the same size and alignment.
    // Reading bits when f was set is valid type-punning.
    unsafe { fb.bits }
}

// Better: use the safe API
fn float_to_bits_safe(f: f32) -> u32 {
    f.to_bits() // safe! preferred
}

